def verify_webhook_signature(payload: bytes, secret: str, signature: str) -> bool:
    """Verify the webhook signature using HMAC-SHA256."""
    expected_signature = hmac.new(
        secret.encode("utf-8"),
        payload,
        hashlib.sha256
    ).hexdigest()

    return hmac.compare_digest(expected_signature, signature)


def parse_payment_notification(body: dict) -> dict:
    """Parse and validate the payment notification payload."""
    # Support multiple provider formats
    payment_data = {}

    # Common fields extraction with support for different provider formats
    if "event" in body:
        # Stripe-like format
        payment_data["event_type"] = body["event"]
        data = body.get("data", {}).get("object", body.get("data", {}))
        payment_data["transaction_id"] = data.get("id", body.get("id"))
        payment_data["amount"] = data.get("amount")
        payment_data["currency"] = data.get("currency", "USD")
        payment_data["status"] = data.get("status")
        payment_data["provider"] = "stripe"
        payment_data["customer_id"] = data.get("customer")
        payment_data["metadata"] = data.get("metadata", {})

    elif "event_type" in body:
        # PayPal-like format
        payment_data["event_type"] = body["event_type"]
        resource = body.get("resource", {})
        payment_data["transaction_id"] = resource.get("id", body.get("id"))
        amount_detail = resource.get("amount", {})
        payment_data["amount"] = amount_detail.get("total") or amount_detail.get("value")
        payment_data["currency"] = amount_detail.get("currency", "USD")
        payment_data["status"] = resource.get("state") or resource.get("status")
        payment_data["provider"] = "paypal"
        payment_data["customer_id"] = resource.get("payer", {}).get("payer_id")
        payment_data["metadata"] = resource.get("custom", {})

    elif "type" in body:
        # Generic provider format
        payment_data["event_type"] = body["type"]
        payment_data["transaction_id"] = body.get("transaction_id") or body.get("id")
        payment_data["amount"] = body.get("amount")
        payment_data["currency"] = body.get("currency", "USD")
        payment_data["status"] = body.get("status")
        payment_data["provider"] = body.get("provider", "unknown")
        payment_data["customer_id"] = body.get("customer_id")
        payment_data["metadata"] = body.get("metadata", {})

    else:
        raise KeyError("event_type or event or type")

    # Validate required fields
    if not payment_data.get("transaction_id"):
        raise KeyError("transaction_id")

    payment_data["received_at"] = datetime.utcnow().isoformat()
    payment_data["raw_payload"] = body

    return payment_data


